code.C:
#include <stdio.h>
#include <string.h>
int main(){
    const char *w1 = "Coding";
    const char *w2 = "on";
    const char *w3 = "CodeChef";
    char sentence[100];
    sprintf(sentence, "%s %s %s", w1, w2, w3);
    const int T = 1; // loop to satisfy the generic requirement
    for(int i=0;i<T;i++){
        printf("%s - %zu\n", w1, strlen(w1));
        printf("%s - %zu\n", w2, strlen(w2));
        printf("%s - %zu\n", w3, strlen(w3));
        printf("%s - %zu\n", sentence, strlen(sentence));
    }
    return 0;
}

